import streamlit as st
import requests

def generate_summary(text, api_key):
    """
    Generates a summary of the given text using the Clause API.

    Args:
        text (str): The text to summarize.
        api_key (str): The Clause API key.

    Returns:
        str: The generated summary, or an error message if the API call fails.
    """
    url = "https://api.clause.io/summarize"  # Replace with the actual Clause API endpoint
    headers = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json"
    }
    data = {
        "text": text
    }
    try:
        response = requests.post(url, headers=headers, json=data)
        response.raise_for_status()  # Raise HTTPError for bad responses (4xx or 5xx)
        return response.json().get("summary", "Summary not found in response.")
    except requests.exceptions.RequestException as e:
        return f"Error: {e}"

def ask_question(summary, question, api_key):
    """
    Asks a question about the summary using the Clause API.

    Args:
        summary (str): The summary text.
        question (str): The question to ask.
        api_key (str): The Clause API key.

    Returns:
        str: The answer to the question, or an error message if the API call fails.
    """
    url = "https://api.clause.io/qa"  # Replace with the actual Clause API endpoint
    headers = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json"
    }
    data = {
        "text": summary,
        "question": question
    }
    try:
        response = requests.post(url, headers=headers, json=data)
        response.raise_for_status()  # Raise HTTPError for bad responses (4xx or 5xx)
        return response.json().get("answer", "Answer not found in response.")
    except requests.exceptions.RequestException as e:
        return f"Error: {e}"


def main():
    st.title("Paper Summarizer")

    api_key = st.text_input("Enter your Clause API Key:", type="password")

    paper_text = st.text_area("Enter the paper text:", height=300)

    if st.button("Generate Summary"):
        if not api_key:
            st.error("Please enter your Clause API key.")
        elif not paper_text:
            st.error("Please enter the paper text.")
        else:
            with st.spinner("Generating summary..."):
                summary = generate_summary(paper_text, api_key)
                st.subheader("Summary:")
                st.write(summary)

                question = st.text_input("Ask a question about the summary:")
                if question:
                    with st.spinner("Answering question..."):
                        answer = ask_question(summary, question, api_key)
                        st.subheader("Answer:")
                        st.write(answer)


if __name__ == "__main__":
    main()

