import streamlit as st
import os
import requests

# Replace with your actual Claude API key
CLAUDE_API_KEY = os.environ.get("CLAUDE_API_KEY")  # Or set it directly if needed

def generate_summary(paper_text):
    """
    Generates a summary of the paper using the Claude API.
    """
    if not CLAUDE_API_KEY:
        st.error("Claude API key not found. Please set the CLAUDE_API_KEY environment variable.")
        return None

    url = "https://api.anthropic.com/v1/messages"
    headers = {
        "Content-Type": "application/json",
        "x-api-key": CLAUDE_API_KEY,
        "Anthropic-Version": "2023-06-01"  # Or the latest version
    }
    data = {
        "model": "claude-v1.3",  # Or your preferred Claude model
        "max_tokens": 1024,  # Adjust as needed
        "messages": [
            {
                "role": "user",
                "content": f"Please provide a concise summary of the following research paper:\n\n{paper_text}"
            }
        ]
    }

    try:
        response = requests.post(url, headers=headers, json=data)
        response.raise_for_status()  # Raise HTTPError for bad responses (4xx or 5xx)
        summary = response.json()['content'][0]['text']
        return summary
    except requests.exceptions.RequestException as e:
        st.error(f"Error calling Claude API: {e}")
        return None
    except KeyError:
        st.error("Error parsing Claude API response. Check the response format.")
        return None

